class Solution:
    def matrixSumQueries(self, n: int, queries) -> int:
        mat = [[0] * n for _ in range(n)]
        for t, idx, val in queries:
            if t == 0:
                for c in range(n):
                    mat[idx][c] = val
            else:
                for r in range(n):
                    mat[r][idx] = val
        return sum(sum(row) for row in mat)

