class Solution:
    def matrixSumQueries(self, n: int, queries) -> int:
        row_done = [False] * n
        col_done = [False] * n
        rows_left = n
        cols_left = n
        total = 0
        for t, idx, val in reversed(queries):
            if t == 0:
                if not row_done[idx]:
                    row_done[idx] = True
                    rows_left -= 1
                    total += val * cols_left
            else:
                if not col_done[idx]:
                    col_done[idx] = True
                    cols_left -= 1
                    total += val * rows_left
        return total

