var matrixSumQueries = function(n, queries) {
    const rowDone = new Array(n).fill(false);
    const colDone = new Array(n).fill(false);
    let rowsLeft = n, colsLeft = n, total = 0;
    for (let i = queries.length - 1; i >= 0; i--) {
        const t = queries[i][0], idx = queries[i][1], val = queries[i][2];
        if (t === 0) {
            if (!rowDone[idx]) {
                rowDone[idx] = true;
                rowsLeft -= 1;
                total += val * colsLeft;
            }
        } else {
            if (!colDone[idx]) {
                colDone[idx] = true;
                colsLeft -= 1;
                total += val * rowsLeft;
            }
        }
    }
    return total;
};
